  1→import { describe, it, expect, beforeEach, vi } from 'vitest';
  2→import { db } from '../services/database';
  3→import { AnalysisResult } from '../types';
  4→
  5→const mockAnalysis: AnalysisResult = {
  6→  url: 'https://example.com/test',
  7→  timestamp: new Date().toISOString(),
  8→  globalScore: 75,
  9→  categories: {},
 10→  recommendations: [],
 11→  aiCitation: {
 12→    before: 'No mention',
 13→    after: 'Mentioned as source',
 14→    probability: 65,
 15→  },
 16→};
 17→
 18→const mockAnalysis2: AnalysisResult = {
 19→  url: 'https://other-site.com/page',
 20→  timestamp: new Date(Date.now() + 1000).toISOString(),
 21→  globalScore: 88,
 22→  categories: {},
 23→  recommendations: [],
 24→  aiCitation: {
 25→    before: 'Partially referenced',
 26→    after: 'Directly cited',
 27→    probability: 82,
 28→  },
 29→};
 30→
 31→describe('database service', () => {
 32→  beforeEach(() => {
 33→    localStorage.clear();
 34→  });
 35→
 36→  it('getAll returns empty array when no data', () => {
 37→    const results = db.getAll();
 38→    expect(results).toEqual([]);
 39→  });
 40→
 41→  it('add stores an analysis and returns updated list', () => {
 42→    const result = db.add(mockAnalysis);
 43→    expect(result).toHaveLength(1);
 44→    expect(result[0].url).toBe('https://example.com/test');
 45→    expect(result[0].globalScore).toBe(75);
 46→  });
 47→
 48→  it('add prepends new items to the list', () => {
 49→    db.add(mockAnalysis);
 50→    const result = db.add(mockAnalysis2);
 51→    expect(result).toHaveLength(2);
 52→    expect(result[0].url).toBe('https://other-site.com/page');
 53→    expect(result[1].url).toBe('https://example.com/test');
 54→  });
 55→
 56→  it('getAll retrieves stored data', () => {
 57→    db.add(mockAnalysis);
 58→    db.add(mockAnalysis2);
 59→    const results = db.getAll();
 60→    expect(results).toHaveLength(2);
 61→  });
 62→
 63→  it('update modifies an existing record', () => {
 64→    db.add(mockAnalysis);
 65→    const updated = db.update(0, { globalScore: 95 });
 66→    expect(updated[0].globalScore).toBe(95);
 67→    expect(updated[0].url).toBe('https://example.com/test');
 68→  });
 69→
 70→  it('clear removes all data', () => {
 71→    db.add(mockAnalysis);
 72→    db.add(mockAnalysis2);
 73→    const result = db.clear();
 74→    expect(result).toEqual([]);
 75→    expect(db.getAll()).toEqual([]);
 76→  });
 77→
 78→  it('getProjectsFromHistory extracts unique domains', () => {
 79→    const history: AnalysisResult[] = [
 80→      { ...mockAnalysis, url: 'https://example.com/page1' },
 81→      { ...mockAnalysis, url: 'https://example.com/page2', globalScore: 80 },
 82→      { ...mockAnalysis2, url: 'https://other-site.com/about' },
 83→    ];
 84→    const projects = db.getProjectsFromHistory(history);
 85→    expect(projects).toHaveLength(2);
 86→    const domains = projects.map(p => p.name);
 87→    expect(domains).toContain('example.com');
 88→    expect(domains).toContain('other-site.com');
 89→  });
 90→
 91→  it('getProjectsFromHistory keeps latest analysis per domain', () => {
 92→    const older: AnalysisResult = {
 93→      ...mockAnalysis,
 94→      url: 'https://example.com/old',
 95→      timestamp: '2024-01-01T00:00:00Z',
 96→      globalScore: 50,
 97→    };
 98→    const newer: AnalysisResult = {
 99→      ...mockAnalysis,
100→      url: 'https://example.com/new',
101→      timestamp: '2025-06-01T00:00:00Z',
102→      globalScore: 90,
103→    };
104→    const projects = db.getProjectsFromHistory([older, newer]);
105→    expect(projects).toHaveLength(1);
106→    expect(projects[0].visibilityScore).toBe(90);
107→  });
108→});
